122	// checked out under .claude/worktrees/, and returned paths must be relative
123	// (never absolute) so the web UI can build valid routes.
124	func TestGraphQLDocuments_SkipsClaudeWorktreesAndUsesRelativePaths(t *testing.T) {
125		xdgDir := t.TempDir()
126		t.Setenv("XDG_DATA_HOME", xdgDir)
127		t.Setenv("DDX_NODE_NAME", "gql-doc-test-node")
128	
129		workDir := setupTestDir(t)
130	
131		files := map[string]string{
132			filepath.Join(workDir, "docs", "resources", "agent-harness-ac.md"): "---\nddx:\n  id: agent-harness-ac\n---\n# Agent Harness AC\n",
133			// Agent scratch copy with frontmatter — must be ignored.
134			filepath.Join(workDir, ".claude", "worktrees", "agent-a0673989", "docs", "resources", "agent-harness-ac.md"): "---\nddx:\n  id: worktree-shadow\n---\n# Shadow Copy\n",
135		}
136		for path, content := range files {
137			if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
138				t.Fatal(err)
139			}
140			if err := os.WriteFile(path, []byte(content), 0o644); err != nil {
141				t.Fatal(err)
142			}
143		}
144	
145		srv := New(":0", workDir)
146	
147		body := `{"query": "{ documents { edges { node { id path } } totalCount } }"}`
148		req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewBufferString(body))
149		req.Header.Set("Content-Type", "application/json")
150		req.RemoteAddr = "127.0.0.1:12345"
151		w := httptest.NewRecorder()
152		srv.Handler().ServeHTTP(w, req)
153	
154		if w.Code != http.StatusOK {
155			t.Fatalf("expected 200, got %d: %s", w.Code, w.Body.String())
156		}
157	
158		var resp struct {
159			Data struct {
160				Documents struct {
161					Edges []struct {
162						Node struct {
163							ID   string `json:"id"`
164							Path string `json:"path"`
165						} `json:"node"`
166					} `json:"edges"`
167				} `json:"documents"`
168			} `json:"data"`
169		}
170		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
171			t.Fatalf("invalid JSON: %v\nbody: %s", err, w.Body.String())
172		}
173	
174		sawCanonical := false
175		for _, e := range resp.Data.Documents.Edges {
176			path := filepath.ToSlash(e.Node.Path)
177			if strings.HasPrefix(path, "/") {
178				t.Errorf("document %q has absolute path %q (leaking filesystem root into web URL)", e.Node.ID, e.Node.Path)
179			}
180			if strings.Contains(path, ".claude/") {
181				t.Errorf("document %q path %q is inside .claude/ (worktree scratch must not be surfaced)", e.Node.ID, e.Node.Path)
182			}
183			if e.Node.ID == "worktree-shadow" {
184				t.Errorf("worktree shadow document was surfaced in documents query")
185			}
186			if e.Node.ID == "agent-harness-ac" {
187				sawCanonical = true
188				if want := "docs/resources/agent-harness-ac.md"; path != want {
189					t.Errorf("got agent-harness-ac path %q, want %q", e.Node.Path, want)
190				}
191			}
192		}
193		if !sawCanonical {
194			t.Error("expected canonical docs/resources/agent-harness-ac.md document in response")
195		}
196	}
